    38â†’	// Run diff
    39â†’	differ := NewDiffer()
    40â†’	result := differ.Diff(sourceData, targetData)
    41â†’	result.Source = "source-org"
    42â†’	result.Target = "target-org"
    43â†’	result.Timestamp = "2026-02-05T19:30:00Z"
    44â†’
    45â†’	// Verify results
