   384â†’// TestFieldLevelDiffs tests detailed field-level difference detection.
   385â†’func TestFieldLevelDiffs(t *testing.T) {
   386â†’	sourceData := &export.Data{
   387â†’		Blueprints: []api.Blueprint{
   388â†’			{
   389â†’				"identifier":  "bp1",
   390â†’				"title":       "Original Title",
   391â†’				"description": "Original Description",
   392â†’				"schema": map[string]interface{}{
   393â†’					"properties": map[string]interface{}{
   394â†’						"name": map[string]interface{}{
   395â†’							"type": "string",
   396â†’						},
   397â†’					},
   398â†’				},
   399â†’			},
   400â†’		},
   401â†’	}
   402â†’
   403â†’	targetData := &export.Data{
   404â†’		Blueprints: []api.Blueprint{
   405â†’			{
   406â†’				"identifier":  "bp1",
   407â†’				"title":       "Updated Title",
   408â†’				"description": "Original Description",
   409â†’				"schema": map[string]interface{}{
   410â†’					"properties": map[string]interface{}{
   411â†’						"name": map[string]interface{}{
   412â†’							"type": "number",
   413â†’						},
   414â†’					},
   415â†’				},
   416â†’			},
   417â†’		},
   418â†’	}
   419â†’
   420â†’	differ := NewDiffer()
   421â†’	result := differ.Diff(sourceData, targetData)
   422â†’
   423â†’	if result.Blueprints.Summary.Modified != 1 {
   424â†’		t.Fatalf("expected 1 modified blueprint, got %d", result.Blueprints.Summary.Modified)
   425â†’	}
   426â†’
   427â†’	modified := result.Blueprints.Modified[0]
   428â†’	if modified.Identifier != "bp1" {
   429â†’		t.Errorf("expected modified identifier 'bp1', got %s", modified.Identifier)
   430â†’	}
   431â†’
   432â†’	// Should have field diffs for title and nested schema property
   433â†’	if len(modified.FieldDiffs) < 2 {
   434â†’		t.Errorf("expected at least 2 field diffs, got %d", len(modified.FieldDiffs))
   435â†’	}
   436â†’
   437â†’	// Check for title diff
   438â†’	foundTitle := false
   439â†’	foundSchema := false
   440â†’	for _, fd := range modified.FieldDiffs {
   441â†’		if fd.Path == "title" {
   442â†’			foundTitle = true
   443â†’			if fd.SourceValue != "Original Title" || fd.TargetValue != "Updated Title" {
   444â†’				t.Errorf("title diff values incorrect: source=%v target=%v",
   445â†’					fd.SourceValue, fd.TargetValue)
   446â†’			}
   447â†’		}
   448â†’		if strings.Contains(fd.Path, "schema.properties.name.type") {
   449â†’			foundSchema = true
   450â†’			if fd.SourceValue != "string" || fd.TargetValue != "number" {
   451â†’				t.Errorf("schema diff values incorrect: source=%v target=%v",
   452â†’					fd.SourceValue, fd.TargetValue)
   453â†’			}
   454â†’		}
   455â†’	}
   456â†’
   457â†’	if !foundTitle {
   458â†’		t.Error("missing title field diff")
   459â†’	}
   460â†’	if !foundSchema {
   461â†’		t.Error("missing schema field diff")
   462â†’	}
   463â†’}
