   505â†’// TestLargeDataset tests comparison with larger datasets.
   506â†’func TestLargeDataset(t *testing.T) {
   507â†’	// Create source with 100 blueprints
   508â†’	var sourceBlueprints []api.Blueprint
   509â†’	for i := 0; i < 100; i++ {
   510â†’		sourceBlueprints = append(sourceBlueprints, api.Blueprint{
   511â†’			"identifier": string(rune('a'+i/26)) + string(rune('a'+i%26)),
   512â†’			"title":      "Blueprint " + string(rune('A'+i/26)) + string(rune('A'+i%26)),
   513â†’		})
   514â†’	}
   515â†’
