    12â†’// ConfigManager manages configuration loading with precedence: CLI flags > env vars > config file.
    13â†’type ConfigManager struct {
    14â†’	configPath string
    15â†’}
    16â†’
    17â†’// ConfigPath returns the configuration file path.
    18â†’func (cm *ConfigManager) ConfigPath() string {
    19â†’	return cm.configPath
    20â†’}
