    22â†’// NewConfigManager creates a new ConfigManager.
    23â†’func NewConfigManager(configPath string) *ConfigManager {
    24â†’	if configPath == "" {
    25â†’		configPath = DefaultConfigPath()
    26â†’	}
    27â†’
    28â†’	// Load .env files (doesn't override existing env vars)
    29â†’	loadEnvFiles()
