    36â†’// loadEnvFiles loads .env files from current directory and ~/.port/.env.
    37â†’func loadEnvFiles() {
    38â†’	// Skip .env loading during tests
    39â†’	if os.Getenv("TESTING") != "" {
    40â†’		return
    41â†’	}
    42â†’
    43â†’	// Try current directory
    44â†’	if _, err := os.Stat(".env"); err == nil {
    45â†’		godotenv.Load(".env")
    46â†’	}
    47â†’
    48â†’	// Try ~/.port/.env
    49â†’	home, err := os.UserHomeDir()
    50â†’	if err == nil {
    51â†’		envPath := filepath.Join(home, ".port", ".env")
    52â†’		if _, err := os.Stat(envPath); err == nil {
    53â†’			godotenv.Load(envPath)
