    58â†’// Load loads configuration with precedence: env vars > config file > defaults.
    59â†’func (cm *ConfigManager) Load() (*Config, error) {
    60â†’	// Start with defaults
    61â†’	cfg := &Config{
    62â†’		DefaultOrg:    "",
    63â†’		Organizations: make(map[string]OrganizationConfig),
    64â†’		Backend: BackendConfig{
    65â†’			URL:     "http://localhost:8080",
    66â†’			Timeout: 300,
    67â†’		},
    68â†’	}
    69â†’
    70â†’	// Load from file if exists
    71â†’	if _, err := os.Stat(cm.configPath); err == nil {
    72â†’		if err := cm.loadFromFile(cfg); err != nil {
    73â†’			return nil, fmt.Errorf("failed to load config file: %w", err)
    74â†’		}
    75â†’	}
    76â†’
    77â†’	// Override with environment variables
    78â†’	cm.loadFromEnv(cfg)
    79â†’
    80â†’	return cfg, nil
    81â†’}
