    22â†’// Validate validates export options.
    23â†’func (o *Options) Validate() error {
    24â†’	if o.OutputPath == "" {
    25â†’		return fmt.Errorf("output_path is required")
    26â†’	}
    27â†’
    28â†’	if o.Format != "" && o.Format != "json" && o.Format != "tar" {
    29â†’		return fmt.Errorf("format must be 'json' or 'tar'")
    30â†’	}
