    60â†’// shouldCollect checks if a resource type should be collected.
    61â†’func shouldCollect(resourceType string, includeResources []string) bool {
    62â†’	if len(includeResources) == 0 {
    63â†’		return true
    64â†’	}
    65â†’
    66â†’	for _, r := range includeResources {
    67â†’		if r == resourceType {
    68â†’			return true
    69â†’		}
    70â†’	}
    71â†’	return false
    72â†’}
