    74â†’// isTimeoutError checks if an error is a timeout error (504 Gateway Timeout).
    75â†’func isTimeoutError(err error) bool {
    76â†’	if err == nil {
    77â†’		return false
    78â†’	}
    79â†’	errStr := strings.ToLower(err.Error())
    80â†’	// Check for various timeout indicators
    81â†’	return strings.Contains(errStr, "504") ||
    82â†’		strings.Contains(errStr, "gateway timeout") ||
    83â†’		strings.Contains(errStr, "timeout_error") ||
    84â†’		strings.Contains(errStr, "request was too long") ||
    85â†’		strings.Contains(errStr, "timeout")
    86â†’}
