    88â†’// Collect collects all data from Port API concurrently.
    89â†’func (c *Collector) Collect(ctx context.Context, opts Options) (*Data, error) {
    90â†’	data := &Data{
    91â†’		Blueprints:    []api.Blueprint{},
    92â†’		Entities:      []api.Entity{},
    93â†’		Scorecards:    []api.Scorecard{},
    94â†’		Actions:       []api.Action{},
    95â†’		Teams:         []api.Team{},
    96â†’		Users:         []api.User{},
    97â†’		Pages:         []api.Page{},
    98â†’		Integrations:  []api.Integration{},
    99â†’		TimeoutErrors: []string{},
   100â†’	}
   101â†’
   102â†’	// Collect blueprints first (needed for other resources)
   103â†’	var blueprints []api.Blueprint
   104â†’	if shouldCollect("blueprints", opts.IncludeResources) {
   105â†’		allBlueprints, err := c.client.GetBlueprints(ctx)
   106â†’		if err != nil {
