   110â†’		// Filter blueprints if specified
   111â†’		if len(opts.Blueprints) > 0 {
   112â†’			blueprintSet := make(map[string]bool)
   113â†’			for _, bpID := range opts.Blueprints {
   114â†’				blueprintSet[bpID] = true
   115â†’			}
