   119â†’					blueprints = append(blueprints, bp)
   120â†’				}
   121â†’			}
   122â†’		} else {
   123â†’			blueprints = allBlueprints
   124â†’		}
   125â†’
   126â†’		data.Blueprints = blueprints
   127â†’	} else {
   128â†’		// Still need blueprints for dependent resources
   129â†’		allBlueprints, err := c.client.GetBlueprints(ctx)
   130â†’		if err != nil {
   131â†’			return nil, fmt.Errorf("failed to get blueprints: %w", err)
   132â†’		}
   133â†’
   134â†’		if len(opts.Blueprints) > 0 {
