   101â†’// normalizeResource normalizes a resource by removing system fields and ensuring consistent structure.
   102â†’func normalizeResource(resource map[string]interface{}, systemFields []string) map[string]interface{} {
   103â†’	normalized := make(map[string]interface{})
   104â†’	removeSet := make(map[string]bool)
   105â†’	for _, f := range systemFields {
   106â†’		removeSet[f] = true
   107â†’	}
   108â†’
   109â†’	for k, v := range resource {
   110â†’		if !removeSet[k] {
   111â†’			normalized[k] = normalizeValue(v)
   112â†’		}
   113â†’	}
   114â†’
   115â†’	return normalized
   116â†’}
   117â†’
   118â†’// normalizeValue recursively normalizes a value for comparison.
   119â†’func normalizeValue(v interface{}) interface{} {
   120â†’	switch val := v.(type) {
   121â†’	case map[string]interface{}:
   122â†’		normalized := make(map[string]interface{})
   123â†’		for k, v := range val {
   124â†’			normalized[k] = normalizeValue(v)
   125â†’		}
   126â†’		return normalized
   127â†’	case []interface{}:
   128â†’		normalized := make([]interface{}, len(val))
   129â†’		for i, item := range val {
   130â†’			normalized[i] = normalizeValue(item)
   131â†’		}
   132â†’		// Sort slice only if ALL elements are strings
   133â†’		if len(normalized) > 0 {
   134â†’			allStrings := true
   135â†’			for _, item := range normalized {
   136â†’				if _, ok := item.(string); !ok {
   137â†’					allStrings = false
   138â†’					break
   139â†’				}
   140â†’			}
   141â†’			if allStrings {
   142â†’				sort.Slice(normalized, func(i, j int) bool {
   143â†’					return normalized[i].(string) < normalized[j].(string)
   144â†’				})
   145â†’			}
   146â†’		}
   147â†’		return normalized
   148â†’	default:
   149â†’		return v
   150â†’	}
   151â†’}
   152â†’
   153â†’// resourcesEqual checks if two resources are equal after normalization.
   154â†’func resourcesEqual(a, b map[string]interface{}, systemFields []string) bool {
   155â†’	normA := normalizeResource(a, systemFields)
   156â†’	normB := normalizeResource(b, systemFields)
   157â†’
   158â†’	// Use JSON marshaling for deep comparison
   159â†’	jsonA, errA := json.Marshal(normA)
   160â†’	jsonB, errB := json.Marshal(normB)
   161â†’
   162â†’	if errA != nil || errB != nil {
   163â†’		// Fallback to reflect.DeepEqual if JSON fails
   164â†’		return reflect.DeepEqual(normA, normB)
   165â†’	}
   166â†’
   167â†’	return string(jsonA) == string(jsonB)
   168â†’}
