   176â†’// compareBlueprints compares import blueprints with current blueprints.
   177â†’func (d *DiffComparer) compareBlueprints(importBPs, currentBPs []api.Blueprint, includeResources []string) (create, update, skip []api.Blueprint) {
   178â†’	if !shouldImport("blueprints", includeResources) {
   179â†’		return nil, nil, nil
   180â†’	}
   181â†’
   182â†’	currentMap := make(map[string]api.Blueprint)
   183â†’	for _, bp := range currentBPs {
   184â†’		if identifier, ok := bp["identifier"].(string); ok {
   185â†’			currentMap[identifier] = bp
   186â†’		}
   187â†’	}
   188â†’
   189â†’	for _, bp := range importBPs {
   190â†’		identifier, ok := bp["identifier"].(string)
   191â†’		if !ok || identifier == "" {
   192â†’			continue
   193â†’		}
   194â†’
   195â†’		// Skip Port-managed blueprints that cannot be modified directly
   196â†’		if portManagedBlueprints[identifier] {
   197â†’			skip = append(skip, bp)
   198â†’			continue
   199â†’		}
   200â†’
   201â†’		// Note: Other system blueprints (starting with _) are included in diff comparison
   202â†’		// so they can be updated with new properties. Creation of feature-flagged
   203â†’		// system blueprints may fail, which is expected behavior.
   204â†’
   205â†’		currentBP, exists := currentMap[identifier]
   206â†’		if !exists {
   207â†’			create = append(create, bp)
   208â†’		} else if !resourcesEqual(bp, currentBP, []string{"createdBy", "updatedBy", "createdAt", "updatedAt", "id"}) {
   209â†’			update = append(update, bp)
   210â†’		} else {
   211â†’			skip = append(skip, bp)
   212â†’		}
   213â†’	}
   214â†’
   215â†’	return create, update, skip
   216â†’}
