    64â†’// shouldCollect checks if a resource type should be collected.
    65â†’func shouldCollect(resourceType string, includeResources []string) bool {
    66â†’	if len(includeResources) == 0 {
    67â†’		return true
    68â†’	}
    69â†’
    70â†’	for _, r := range includeResources {
