    78â†’// isTimeoutError checks if an error is a timeout error (504 Gateway Timeout).
    79â†’func isTimeoutError(err error) bool {
    80â†’	if err == nil {
    81â†’		return false
    82â†’	}
    83â†’	errStr := strings.ToLower(err.Error())
    84â†’	// Check for various timeout indicators
    85â†’	return strings.Contains(errStr, "504") ||
    86â†’		strings.Contains(errStr, "gateway timeout") ||
    87â†’		strings.Contains(errStr, "timeout_error") ||
    88â†’		strings.Contains(errStr, "request was too long") ||
    89â†’		strings.Contains(errStr, "timeout")
    90â†’}
