    96â†’		Entities:             []api.Entity{},
    97â†’		Scorecards:           []api.Scorecard{},
    98â†’		Actions:              []api.Action{},
    99â†’		Teams:                []api.Team{},
   100â†’		Users:                []api.User{},
   101â†’		Pages:                []api.Page{},
   102â†’		Integrations:         []api.Integration{},
   103â†’		TimeoutErrors:        []string{},
   104â†’		BlueprintPermissions: make(map[string]api.Permissions),
   105â†’		ActionPermissions:    make(map[string]api.Permissions),
   106â†’	}
   107â†’
   108â†’	// Collect blueprints first (needed for other resources)
   109â†’	var blueprints []api.Blueprint
   110â†’	if shouldCollect("blueprints", opts.IncludeResources) {
   111â†’		allBlueprints, err := c.client.GetBlueprints(ctx)
   112â†’		if err != nil {
   113â†’			return nil, fmt.Errorf("failed to get blueprints: %w", err)
   114â†’		}
   115â†’
   116â†’		// Filter blueprints if specified
   117â†’		if len(opts.Blueprints) > 0 {
   118â†’			blueprintSet := make(map[string]bool)
   119â†’			for _, bpID := range opts.Blueprints {
   120â†’				blueprintSet[bpID] = true
   121â†’			}
   122â†’
   123â†’			for _, bp := range allBlueprints {
   124â†’				if identifier, ok := bp["identifier"].(string); ok && blueprintSet[identifier] {
   125â†’					blueprints = append(blueprints, bp)
   126â†’				}
   127â†’			}
   128â†’		} else {
   129â†’			blueprints = allBlueprints
   130â†’		}
   131â†’
   132â†’		data.Blueprints = blueprints
   133â†’	} else {
   134â†’		// Still need blueprints for dependent resources
   135â†’		allBlueprints, err := c.client.GetBlueprints(ctx)
   136â†’		if err != nil {
   137â†’			return nil, fmt.Errorf("failed to get blueprints: %w", err)
   138â†’		}
   139â†’
   140â†’		if len(opts.Blueprints) > 0 {
   141â†’			blueprintSet := make(map[string]bool)
   142â†’			for _, bpID := range opts.Blueprints {
   143â†’				blueprintSet[bpID] = true
   144â†’			}
   145â†’
   146â†’			for _, bp := range allBlueprints {
   147â†’				if identifier, ok := bp["identifier"].(string); ok && blueprintSet[identifier] {
   148â†’					blueprints = append(blueprints, bp)
   149â†’				}
   150â†’			}
