   152â†’			blueprints = allBlueprints
   153â†’		}
   154â†’	}
   155â†’
   156â†’	// Use errgroup for concurrent collection
   157â†’	g, ctx := errgroup.WithContext(ctx)
   158â†’	var mu sync.Mutex
   159â†’	var timeoutErrors []string // Track timeout errors separately
   160â†’
   161â†’	// Collect entities, scorecards, and actions concurrently per blueprint
   162â†’	for _, blueprint := range blueprints {
   163â†’		bp := blueprint
   164â†’		bpID, ok := bp["identifier"].(string)
   165â†’		if !ok {
   166â†’			continue
   167â†’		}
   168â†’
   169â†’		// Collect entities
   170â†’		if !opts.SkipEntities && shouldCollect("entities", opts.IncludeResources) {
   171â†’			g.Go(func() error {
   172â†’				entities, err := c.client.GetEntities(ctx, bpID, nil)
   173â†’				if err != nil {
   174â†’					// Handle expected errors gracefully
   175â†’					if strings.Contains(err.Error(), "410 Gone") {
