   214â†’				for i := range scorecards {
   215â†’					if _, exists := scorecards[i]["blueprintIdentifier"]; !exists {
   216â†’						scorecards[i]["blueprintIdentifier"] = bpID
   217â†’					}
   218â†’				}
   219â†’
   220â†’				mu.Lock()
   221â†’				data.Scorecards = append(data.Scorecards, scorecards...)
   222â†’				mu.Unlock()
   223â†’				return nil
   224â†’			})
   225â†’		}
   226â†’
   227â†’		// Collect actions
